// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

// Package quota implements a controller that enforces per-namespace limits on
// the number of CiliumNetworkPolicy resources.
package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces a
// configurable per-namespace limit on how many policies can exist.
type PolicyQuotaController struct {
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace       int

	mu       sync.RWMutex
	nsCount  map[string]int
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
//
//   - client is unused directly; the informer is provided via cnpResource.
//   - cnpResource is the resource.Resource used to watch CiliumNetworkPolicy objects.
//   - maxPerNamespace is the maximum number of CiliumNetworkPolicy resources
//     permitted in any single namespace. A value of 0 means no limit.
func NewPolicyQuotaController(
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		ciliumNetworkPolicies: cnpResource,
		maxPerNamespace:       maxPerNamespace,
		nsCount:               make(map[string]int),
	}
}

// Run starts the controller loop. It blocks until ctx is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	events := c.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-events:
			if !ok {
				return
			}

			switch event.Kind {
			case resource.Sync:
				log.Debug("CiliumNetworkPolicy store synced")
				event.Done(nil)

			case resource.Upsert:
				ns := event.Object.GetNamespace()
				key := event.Key

				c.mu.Lock()
				// Track by key to avoid double-counting on re-upsert: store
				// the namespace for each known key so we can adjust if it
				// changes, though in practice namespace is immutable.
				c.nsCount[ns]++
				c.mu.Unlock()

				log.WithFields(logrus.Fields{
					logfields.K8sNamespace: ns,
					"key":                  key,
					"count":                c.nsCount[ns],
				}).Debug("CiliumNetworkPolicy upserted")

				event.Done(nil)

			case resource.Delete:
				ns := event.Object.GetNamespace()
				key := event.Key

				c.mu.Lock()
				if c.nsCount[ns] > 0 {
					c.nsCount[ns]--
				}
				if c.nsCount[ns] == 0 {
					delete(c.nsCount, ns)
				}
				c.mu.Unlock()

				log.WithFields(logrus.Fields{
					logfields.K8sNamespace: ns,
					"key":                  key,
				}).Debug("CiliumNetworkPolicy deleted")

				event.Done(nil)
			}
		}
	}
}

// CheckQuota returns an error if the number of CiliumNetworkPolicy resources
// in namespace already meets or exceeds the configured limit. A limit of 0
// means unlimited.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPerNamespace == 0 {
		return nil
	}

	c.mu.RLock()
	count := c.nsCount[namespace]
	c.mu.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf(
			"namespace %q has reached the CiliumNetworkPolicy quota of %d",
			namespace, c.maxPerNamespace,
		)
	}
	return nil
}

// NamespaceCount returns the current number of CiliumNetworkPolicy resources
// tracked for the given namespace. This is primarily useful for testing.
func (c *PolicyQuotaController) NamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.nsCount[namespace]
}

// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
)

// fakeResource is a minimal implementation of resource.Resource[T] for testing.
type fakeResource struct {
	ch chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func newFakeResource() *fakeResource {
	return &fakeResource{
		ch: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 16),
	}
}

func (f *fakeResource) Events(_ context.Context, _ ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return f.ch
}

func (f *fakeResource) Observe(_ context.Context, next func(resource.Event[*cilium_v2.CiliumNetworkPolicy]), complete func(error)) {
	go func() {
		for e := range f.ch {
			next(e)
		}
		complete(nil)
	}()
}

func (f *fakeResource) Store(_ context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, nil
}

func (f *fakeResource) send(kind resource.EventKind, ns, name string) {
	done := make(chan struct{})
	f.ch <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: kind,
		Key:  resource.NewKey(&cilium_v2.CiliumNetworkPolicy{ObjectMeta: metav1.ObjectMeta{Namespace: ns, Name: name}}),
		Object: &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Namespace: ns,
				Name:      name,
			},
		},
		Done: func(err error) { close(done) },
	}
	<-done
}

func (f *fakeResource) sendSync() {
	done := make(chan struct{})
	f.ch <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Sync,
		Done:   func(err error) { close(done) },
		Object: &cilium_v2.CiliumNetworkPolicy{},
	}
	<-done
}

// runController starts the controller in the background and returns a cancel
// function that stops it.
func runController(t *testing.T, c *PolicyQuotaController) context.CancelFunc {
	t.Helper()
	ctx, cancel := context.WithCancel(context.Background())
	go c.Run(ctx)
	return cancel
}

func TestNewPolicyQuotaController(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 5)
	require.NotNil(t, c)
	assert.Equal(t, 5, c.maxPerNamespace)
}

func TestCheckQuota_NoLimit(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 0)

	// With limit 0 (unlimited), CheckQuota should always return nil.
	assert.NoError(t, c.CheckQuota("any-namespace"))
}

func TestCheckQuota_UnderLimit(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 3)

	cancel := runController(t, c)
	defer cancel()

	fake.send(resource.Upsert, "ns1", "policy-1")

	assert.NoError(t, c.CheckQuota("ns1"))
}

func TestCheckQuota_AtLimit(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 2)

	cancel := runController(t, c)
	defer cancel()

	fake.send(resource.Upsert, "ns1", "policy-1")
	fake.send(resource.Upsert, "ns1", "policy-2")

	err := c.CheckQuota("ns1")
	require.Error(t, err)
	assert.Contains(t, err.Error(), "ns1")
	assert.Contains(t, err.Error(), "2")
}

func TestCheckQuota_PerNamespaceIsolation(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 1)

	cancel := runController(t, c)
	defer cancel()

	fake.send(resource.Upsert, "ns1", "policy-1")

	// ns1 is at the limit.
	assert.Error(t, c.CheckQuota("ns1"))
	// ns2 is untouched.
	assert.NoError(t, c.CheckQuota("ns2"))
}

func TestNamespaceCount_AfterDelete(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 5)

	cancel := runController(t, c)
	defer cancel()

	fake.send(resource.Upsert, "ns1", "policy-1")
	fake.send(resource.Upsert, "ns1", "policy-2")
	assert.Equal(t, 2, c.NamespaceCount("ns1"))

	fake.send(resource.Delete, "ns1", "policy-1")
	assert.Equal(t, 1, c.NamespaceCount("ns1"))

	fake.send(resource.Delete, "ns1", "policy-2")
	assert.Equal(t, 0, c.NamespaceCount("ns1"))

	// After all policies deleted, quota check should pass.
	assert.NoError(t, c.CheckQuota("ns1"))
}

func TestSyncEvent(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 5)

	cancel := runController(t, c)
	defer cancel()

	// Sync event should be handled without panicking.
	fake.sendSync()
}

func TestRun_ContextCancellation(t *testing.T) {
	fake := newFakeResource()
	c := NewPolicyQuotaController(fake, 5)

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	done := make(chan struct{})
	go func() {
		defer close(done)
		c.Run(ctx)
	}()

	select {
	case <-done:
		// Run returned after context cancelled — expected.
	case <-time.After(time.Second):
		t.Fatal("Run did not return after context cancellation")
	}
}

