// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

// Package quota implements a controller that enforces per-namespace limits on
// the number of CiliumNetworkPolicy resources.
package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces a
// configurable per-namespace limit on how many policies can exist.
type PolicyQuotaController struct {
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace       int

	mu      sync.RWMutex
	nsCount map[string]int
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
//
//   - cnpResource is the resource.Resource used to watch CiliumNetworkPolicy objects.
//   - maxPerNamespace is the maximum number of CiliumNetworkPolicy resources
//     permitted in any single namespace. A value of 0 means no limit.
func NewPolicyQuotaController(
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		ciliumNetworkPolicies: cnpResource,
		maxPerNamespace:       maxPerNamespace,
		nsCount:               make(map[string]int),
	}
}

// Run starts the controller loop. It blocks until ctx is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	events := c.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-events:
			if !ok {
				return
			}

			switch event.Kind {
			case resource.Sync:
				log.Debug("CiliumNetworkPolicy store synced")
				event.Done(nil)

			case resource.Upsert:
				ns := event.Object.GetNamespace()
				key := event.Key

				c.mu.Lock()
				c.nsCount[ns]++
				count := c.nsCount[ns]
				c.mu.Unlock()

				log.WithFields(logrus.Fields{
					logfields.K8sNamespace: ns,
					"key":                  key,
					"count":                count,
				}).Debug("CiliumNetworkPolicy upserted")

				event.Done(nil)

			case resource.Delete:
				ns := event.Object.GetNamespace()
				key := event.Key

				c.mu.Lock()
				if c.nsCount[ns] > 0 {
					c.nsCount[ns]--
				}
				if c.nsCount[ns] == 0 {
					delete(c.nsCount, ns)
				}
				c.mu.Unlock()

				log.WithFields(logrus.Fields{
					logfields.K8sNamespace: ns,
					"key":                  key,
				}).Debug("CiliumNetworkPolicy deleted")

				event.Done(nil)
			}
		}
	}
}

// CheckQuota returns an error if the number of CiliumNetworkPolicy resources
// in namespace already meets or exceeds the configured limit. A limit of 0
// means unlimited.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPerNamespace == 0 {
		return nil
	}

	c.mu.RLock()
	count := c.nsCount[namespace]
	c.mu.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf(
			"namespace %q has reached the CiliumNetworkPolicy quota of %d",
			namespace, c.maxPerNamespace,
		)
	}
	return nil
}

// NamespaceCount returns the current number of CiliumNetworkPolicy resources
// tracked for the given namespace. This is primarily useful for testing.
func (c *PolicyQuotaController) NamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.nsCount[namespace]
}

